sql:
SELECT user_id, SUM(num_videos) AS total_videos_uploaded
FROM bulk_uploads
GROUP BY user_id;

SELECT title, duration,
       (SELECT AVG(duration) FROM videos) AS avg_video_duration
FROM videos;

SELECT SUM(share_count) AS total_shares
FROM video_shares
WHERE video_id = 1;

SELECT tag_name
FROM video_tags
WHERE tag_id = 1;

SELECT video_id, engagement_score
FROM video_analytics
WHERE engagement_score = (SELECT MAX(engagement_score) FROM video_analytics);

SELECT video_id, views
FROM videos
ORDER BY views DESC;

SELECT upload_time, num_videos
FROM bulk_uploads
WHERE upload_id = 1;

SELECT platform_id, share_count
FROM video_shares
WHERE video_id = 0;

SELECT comment_text
FROM video_comments
WHERE video_id = 1;

SELECT MAX(engagement_score) AS max_engagement
FROM video_analytics
WHERE video_id = 1;

SELECT COUNT(*) AS num_uploads
FROM bulk_uploads
WHERE user_id = 1;
